// Config: how many posts to publish per run, per domain
const PUBLISH_LIMIT_PER_DOMAIN = 1;

// Domains and their Ghost URLs + Admin API keys (from env)
const domains = [
  {
    domain: 'mostlyprompt.com',
    ghostUrl: 'https://mostlyprompt.com',
    adminKey: $env.GHOST_MOSTLYPROMPT_ADMIN_API_KEY
  },
  {
    domain: 'fellowcoder.com', 
    ghostUrl: 'https://fellowcoder.com',
    adminKey: $env.GHOST_FELLOWCODER_ADMIN_API_KEY
  }
];

// Only include domains with API keys configured
const activeDomains = domains.filter(d => d.adminKey && d.adminKey.length > 0);

return activeDomains.map(d => ({ json: { ...d, publishLimit: PUBLISH_LIMIT_PER_DOMAIN } }));

// Flatten: for each domain response, extract posts
const items = $input.all();
const toPublish = [];

for (const item of items) {
  const posts = item.json.posts || [];
  const ghostUrl = item.json.ghostUrl || $('Fetch Oldest Drafts').item.json.ghostUrl;
  const adminKey = item.json.adminKey || $('Fetch Oldest Drafts').item.json.adminKey;

  for (const post of posts) {
    toPublish.push({
      json: {
        postId: post.id,
        postTitle: post.title,
        updated_at: post.updated_at,
        ghostUrl,
        adminKey
      }
    });
  }
}

return toPublish.length > 0 ? toPublish : [{ json: { noPostsFound: true } }];

